// @1/+esm bundle 失败,使用官方 UMD 文件;先建立可见挂载状态再载入
const el = document.getElementById('sheet'); el.style.height = '480px'; el.textContent = 'Loading spreadsheet…';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/x-data-spreadsheet@1.1.9/dist/xspreadsheet.css'; document.head.appendChild(css);
await import('https://cdn.jsdelivr.net/npm/x-data-spreadsheet@1.1.9/dist/xspreadsheet.js');
const createSheet = globalThis.x_spreadsheet; if (typeof createSheet !== 'function') throw new Error('x_spreadsheet factory unavailable');
el.textContent = ''; const sheet = createSheet(el, { mode: data.mode ?? 'edit', view: { height: () => 480, width: () => el.clientWidth || 600 } });
const sheets = Array.isArray(data.sheets) ? data.sheets : [data.sheets ?? { name:'Sheet1', rows:{} }]; sheet.loadData(sheets);

